"use strict";parserFactory.register("peachpitting.com",()=>new PeachpittingParser);class PeachpittingParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div.pt-cv-wrapper a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div#wtr-content")}extractTitleImpl(e){return e.querySelector("h3.elementor-heading-title")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,".pp-multiple-authors-wrapper"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("div.post-title h2")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div#primary")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.elementor-text-editor")].slice(1,2)}}